1	interface QuoteItem {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	}
6	
7	interface QuoteStep {
8	  op: "quote";
9	  items: QuoteItem[];
10	}
11	
12	interface DamageEntry {
13	  itemType: string;
14	  amount: number;
15	}
16	
17	interface ClaimStep {
18	  op: "claim";
19	  policy: number;
20	  incident: {
21	    cause: string;
22	    damages: DamageEntry[];
23	  };
24	}
25	
26	type Step = QuoteStep | ClaimStep;
27	
28	interface Scenario {
29	  customer: { yearsWithMHPCO: number };
30	  steps: Step[];
31	}
32	
33	type QuoteResult = { premium: number };
34	type ClaimResult = { payout: number };
35	type StepResult = QuoteResult | ClaimResult;
36	
37	const BASE_PREMIUM: Record<string, number> = {
38	  amulet: 60,
39	  sword: 100,
40	  rune: 25,
41	  moonstone: 25,
42	};
43	
44	const FIRST_INSURANCE_RATE = 0.1;
45	const PROCESSING_FEE = 5;
46	
47	const CURSE_SURCHARGE_RATE = 0.5;
48	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
49	const HIGH_ENCHANTMENT_THRESHOLD = 5;
50	const LOYALTY_DISCOUNT_RATE = 0.2;
51	const LOYALTY_THRESHOLD_YEARS = 2;
52	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
53	
54	// Component-block pricing: 3 alike components of the same type (e.g. 3 runes
55	// or 3 moonstones) sold together are priced as a 60 G block instead of
56	// 3 × 25 = 75 G. Adjustment is applied to policy base for each component
57	// type with exactly 3 instances.
58	const COMPONENT_BLOCK_SIZE = 3;
59	const COMPONENT_BLOCK_PRICE = 60;
60	const COMPONENT_TYPES = ["rune", "moonstone"];
61	
62	function sumOver<T>(xs: T[], f: (x: T) => number): number {
63	  return xs.reduce((total, x) => total + f(x), 0);
64	}
65	
66	// MHPCO rounds quote premiums UP (in the office's favor).
67	function roundUpInFavorOfOffice(amount: number): number {
68	  return Math.ceil(amount);
69	}
70	
71	function basePremium(type: string): number {
72	  return BASE_PREMIUM[type] ?? 0;
73	}
74	
75	function itemBasePremium(item: QuoteItem): number {
76	  return basePremium(item.type);
77	}
78	
79	// Per-type adjustment when exactly COMPONENT_BLOCK_SIZE items of `type` are
80	// present in the step: replace raw N × base with the flat block price.
81	function componentBlockAdjustment(items: QuoteItem[]): number {
82	  return sumOver(COMPONENT_TYPES, (type) => {
83	    const count = items.filter((x) => x.type === type).length;
84	    return count === COMPONENT_BLOCK_SIZE
85	      ? COMPONENT_BLOCK_PRICE - COMPONENT_BLOCK_SIZE * basePremium(type)
86	      : 0;
87	  });
88	}
89	
90	function itemSurcharges(item: QuoteItem): number {
91	  const base = itemBasePremium(item);
92	  const curseSurcharge = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
93	  const highEnchantmentSurcharge =
94	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
95	      ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
96	      : 0;
97	  return curseSurcharge + highEnchantmentSurcharge;
98	}
99	
100	function priceQuoteStep(
101	  step: QuoteStep,
102	  yearsWithMHPCO: number,
103	  isFollowUp: boolean,
104	): QuoteResult {
105	  const policyBase =
106	    sumOver(step.items, itemBasePremium) + componentBlockAdjustment(step.items);
107	  const itemSurchargeTotal = sumOver(step.items, itemSurcharges);
108	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
109	  const loyaltyDiscount =
110	    yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
111	      ? policyBase * LOYALTY_DISCOUNT_RATE
112	      : 0;
113	  const followUpDiscount = isFollowUp
114	    ? policyBase * FOLLOW_UP_DISCOUNT_RATE
115	    : 0;
116	  const premium = roundUpInFavorOfOffice(
117	    policyBase +
118	      itemSurchargeTotal +
119	      firstInsurance -
120	      loyaltyDiscount -
121	      followUpDiscount +
122	      PROCESSING_FEE,
123	  );
124	  return { premium };
125	}
126	
127	const DEDUCTIBLE_PER_DAMAGE = 100;
128	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
129	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
130	
131	// Payout for a single damage entry: full reimbursement minus a flat
132	// per-damage deductible. Upcoming clauses (high-enchantment 50%,
133	// dragon-material) will compose here, mirroring how `itemSurcharges` is
134	// the home for per-item surcharges in `priceQuoteStep`.
135	function damagePayout(damage: DamageEntry, insuredItem: QuoteItem): number {
136	  const reimbursement =
137	    (insuredItem.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD
138	      ? damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
139	      : damage.amount;
140	  return reimbursement - DEDUCTIBLE_PER_DAMAGE;
141	}
142	
143	function processClaimStep(step: ClaimStep, policyItems: QuoteItem[]): ClaimResult {
144	  const payout = sumOver(step.incident.damages, (damage) => {
145	    const insuredItem = policyItems.find((item) => item.type === damage.itemType);
146	    return damagePayout(damage, insuredItem!);
147	  });
148	  return { payout };
149	}
150	
151	export function runScenario(scenario: Scenario): {
152	  results: StepResult[];
153	} {
154	  const results = scenario.steps.map((step, index) => {
155	    if (step.op === "quote") {
156	      return priceQuoteStep(step, scenario.customer.yearsWithMHPCO, index > 0);
157	    }
158	    const policyStep = scenario.steps[step.policy] as QuoteStep;
159	    return processClaimStep(step, policyStep.items);
160	  });
161	  return { results };
162	}
